```json
{
  "global": "Navigate the airline membership program website to systematically identify all membership tiers and extract their respective benefits, then organize and verify the comparison.",
  "subtasks": [
    {
      "subtask": "Locate and access the membership program page",
      "atomics": [
        "Navigate to the airline website homepage",
        "Find and click on the Membership or Loyalty Program link in the main navigation",
        "Wait for the membership program overview page to load and display tier options"
      ]
    },
    {
      "subtask": "Identify all available membership tiers",
      "atomics": [
        "Scan the membership overview page to locate all tier name displays",
        "Enumerate all distinct membership tier levels (e.g., Bronze, Silver, Gold, Platinum, Diamond)",
        "Verify the complete count of tiers available"
      ]
    },
    {
      "subtask": "Extract benefit details for each tier",
      "atomics": [
        "Click on each tier name or 'View Benefits' link to access the detailed benefits page",
        "Extract specific benefits: miles earning multiplier, free seat upgrade allowances, lounge access, priority boarding, baggage allowances, hotel/car rental benefits, companion pass benefits",
        "Record all benefits in structured format for comparison"
      ]
    },
    {
      "subtask": "Organize benefits in a comparable format",
      "atomics": [
        "Create a comparison matrix with membership tiers as columns and benefit categories as rows",
        "Populate each cell with the specific benefit value for that tier",
        "Annotate unique or tier-exclusive benefits"
      ]
    },
    {
      "subtask": "Verify completeness and accuracy",
      "atomics": [
        "Cross-check that all identified tiers appear in the comparison matrix",
        "Ensure no major benefit categories are missing from the comparison",
        "Validate benefit values against the source website pages"
      ]
    }
  ],
  "global_atomics": [
    "Confirm the comparison table accounts for all membership tier levels offered",
    "Ensure the final comparison is in a side-by-side format enabling direct tier benefit comparison",
    "Output the membership tier benefits comparison in a persistent structured format"
  ],
  "gold_actions": {
    "global": "Click through the airline membership program pages, extract all tier names and specific benefit values, compile into a structured comparison table, and validate that all tiers and benefit categories are represented.",
    "subtasks": [
      {
        "subtask": "Locate and access the membership program page",
        "atomics": [
          "Click on 'Membership' or 'Loyalty Program' link in the airline website header navigation",
          "Navigate to the membership program landing page",
          "Verify the page displays membership tier names and benefit overview sections"
        ]
      },
      {
        "subtask": "Identify all available membership tiers",
        "atomics": [
          "Identify tier names displayed on the membership overview page",
          "List all membership levels (e.g., Bronze, Silver, Gold, Platinum, Diamond or equivalent)",
          "Record the total number of distinct tiers available"
        ]
      },
      {
        "subtask": "Extract benefit details for each tier",
        "atomics": [
          "Click on each tier's 'View Details' or 'Learn More' button to access the full benefits listing",
          "Extract benefit values for: base/bonus miles earning rate, annual free seat upgrade allowances, lounge access eligibility, priority boarding, baggage policy, hotel/car rental partner discounts, and companion ticket benefits",
          "Compile all benefits into a structured data format indexed by tier name"
        ]
      },
      {
        "subtask": "Organize benefits in a comparable format",
        "atomics": [
          "Build a comparison table with tier names as column headers and benefit categories as row labels",
          "Fill each cell with the specific benefit value from the extracted data",
          "Mark or highlight benefits that are unique to specific tiers"
        ]
      },
      {
        "subtask": "Verify completeness and accuracy",
        "atomics": [
          "Check the comparison table contains all tiers identified in step 2",
          "Verify all standard benefit categories (earning multiplier, upgrades, lounge, boarding, baggage, partners) are present",
          "Cross-validate benefit values by reviewing source tier pages again"
        ]
      }
    ],
    "global_atomics": [
      "Confirm the final comparison includes all membership tiers offered by the airline",
      "Ensure the comparison table format allows clear, direct side-by-side benefit comparison across all tiers",
      "Save the membership tier benefits comparison as a structured output (table or JSON format)"
    ]
  }
}
